/// Look up symmetry operations by International Tables number (1-230).
/// Returns parsed SymmetryOperation objects.
pub fn lookup_symmetry_operations_by_number(
    number: u16,
) -> Result<Vec<SymmetryOperation>, CifError> {
    if !(1..=230).contains(&number) {
        return Err(CifError::SymmetryParse(format!(
            "Space group number {} is out of range (1-230)",
            number
        )));
    }
    let entry = &SPACE_GROUPS[(number - 1) as usize];
    entry
        .symops
        .iter()
        .map(|s| {
            parse_symmetry_operation(s).map_err(|e| {
                CifError::SymmetryParse(format!(
                    "Failed to parse space group {} operation '{}': {}",
                    number, s, e
                ))
            })
        })
        .collect()
}

/// Look up symmetry operations by Hermann-Mauguin symbol.
/// The symbol is matched case-insensitively with spaces stripped.
pub fn lookup_symmetry_operations_by_hm(symbol: &str) -> Result<Vec<SymmetryOperation>, CifError> {
    let normalized: String = symbol
        .chars()
        .filter(|c| !c.is_whitespace())
        .collect::<String>()
        .to_lowercase();
    for entry in &SPACE_GROUPS {
        let entry_normalized: String = entry
            .hermann_mauguin
            .chars()
            .filter(|c| !c.is_whitespace())
            .collect::<String>()
            .to_lowercase();
        if entry_normalized == normalized {
            return entry
                .symops
                .iter()
                .map(|s| {
                    parse_symmetry_operation(s).map_err(|e| {
                        CifError::SymmetryParse(format!(
                            "Failed to parse space group '{}' operation '{}': {}",
                            symbol, s, e
                        ))
                    })
                })
                .collect();
        }
    }
    Err(CifError::SymmetryParse(format!(
        "Unknown Hermann-Mauguin symbol: '{}'",
        symbol
    )))
}
